VALUES
  ('real-estate-moex-02862', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依內政部所制定「預售屋買賣定型化契約應記載及不得記載事項」之規定，買方如有違約，賣方不得約 定請求超過民法第205條所訂多少百分比年利率之利息？', '["1%", "5%", "10%", "20%"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02863', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依內政部所制定「不動產委託銷售契約書範本」之規定，如買方簽立「要約書」，受託人應於多久內將 該要約書轉交委託人，不得隱瞞或扣留？', '["12小時內", "24小時內", "36小時內", "48小時內"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02864', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '以下有關不動產經紀業之規定，何者有誤？', '["經紀人員對於因業務知悉或持有之他人秘密，不得無故洩漏，如有違反，應予撤銷經紀人證書之懲罰", "曾經營經紀業，經主管機關撤銷許可，自撤銷之日起未滿5年者，原則上不得再申請經營經紀業", "不動產經紀業或經紀人員不得收取差價或其他報酬，如有違反，其已收取之差價或其他報酬應於加計 利息後加倍返還支付人", "不動產經紀業僱用未具備經紀人員資格者從事仲介業務時，最高可處新臺幣30萬元之罰鍰"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02865', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '公平交易委員會依規定進行調查時，受調查者於期限內如無正當理由拒絕調查、拒不到場陳述意見，再 經通知，無正當理由連續拒絕者，公平交易委員會得繼續通知調查，並按次連續處新臺幣多少萬元之罰 鍰？', '["10,000元以上30,000元以下", "30,000以上50,000元以下", "50,000元以上100,000元以下", "50,000元以上500,000元以下"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02866', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '多層次傳銷，其參加人如取得佣金、獎金或其他經濟利益，主要係基於介紹他人加入，而非基於其所推 廣或銷售商品或勞務之合理市價者，處行為人幾年以下之有期徒刑？', '["1年以下", "2年以下", "3年以下", "5年以下"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02867', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依公平交易法之規定，事業因侵害行為受有利益者，被害人所請求之損害賠償額得如何計算？', '["以被害人所受之損害額為限", "以被害人所受之損害額及所失之利益額為限", "不得超過被害人所受損害額之3倍", "得專依事業所受之該項利益計算損害額"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02868', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '以下有關公平交易法之規定，何者有誤？', '["事業不得在商品或其廣告上，或以其他使公眾得知之方法，對於商品之價格、數量等，為虛偽不實或 引人錯誤之表示或表徵", "事業對於載有虛偽不實或引人錯誤表示之商品，不得販賣、運送、輸出或輸入", "廣告代理業在明知或可得知情形下，仍製作或設計有引人錯誤之廣告，與廣告主負連帶損害賠償責任", "廣告媒體業在明知或可得知其所傳播或刊載之廣告有引人錯誤之虞，仍予傳播或刊載，不必與廣告主 負連帶損害賠償責任"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02869', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '公平交易法中所定之損害賠償請求權，自請求權人知有行為及賠償義務人時起，幾年不行使而消滅？', '["1年", "2年", "10年", "15年"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02870', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '以脅迫、利誘或其他不正當方法，獲取他事業之產銷機密、交易相對人資料或其他有關技術秘密之行為， 經中央主管機關命其停止而逾期未停止者，得處行為人幾年以下有期徒刑？', '["5年", "2年", "1年", "半年"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02871', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '下列何項原則不屬於消費者保護法中有關定型化契約的基本原則規定？', '["契約中所用之條款，應本平等互惠之原則", "契約條款如有疑義時，應為有利於消費者之解釋原則", "契約條款應有價格合理之保證原則", "對消費者之損害賠償責任，不得預先約定限制或免除"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
